var items = $input.all();
var results = [];
var now = new Date().toISOString();
var keywords = ['ai', 'artificial intelligence', 'machine learning', 'edtech', 'education technology', 'student management', 'academic', 'marking', 'assessment', 'lms', 'learning management', 'saas', 'enterprise software'];

for (var i = 0; i < items.length; i++) {
  var data = items[i].json;
  var title = data.title || '';
  var summary = (data.contentSnippet || data.description || '').replace(/<[^>]*>/g, '');
  var text = (title + ' ' + summary).toLowerCase();

  // Check if relevant to AI/EdTech
  var relevant = false;
  for (var k = 0; k < keywords.length; k++) {
    if (text.indexOf(keywords[k]) >= 0) { relevant = true; break; }
  }
  if (!relevant) continue;

  results.push({ json: {
    signal_type: 'market-intel',
    title: title,
    summary: summary.substring(0, 500),
    source_url: data.link || data.url || '',
    region: 'UK',
    relevance_score: 3,
    discovered_at: now
  }});
}

// Deduplicate
var seen = {};
var unique = [];
for (var j = 0; j < results.length; j++) {
  var key = results[j].json.title.toLowerCase();
  if (!seen[key]) { seen[key] = true; unique.push(results[j]); }
}

return unique.length > 0 ? unique : [{ json: { signal_type: 'market-intel', title: 'No relevant signals this week', summary: '', source_url: '', region: 'UK', relevance_score: 1, discovered_at: now } }];

var signals = $('Filter & Categorise').all();
var now = new Date().toLocaleDateString('en-GB', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
var html = '<div style="font-family:Arial,sans-serif;max-width:700px;margin:0 auto;">';
html += '<h1 style="color:#2c3e50;">AI & EdTech Market Intelligence</h1>';
html += '<p style="color:#666;">' + now + ' &bull; ' + signals.length + ' signals</p><hr>';
html += '<ul style="list-style:none;padding:0;">';
for (var i = 0; i < signals.length; i++) {
  var s = signals[i].json;
  html += '<li style="margin-bottom:10px;padding:8px;background:#f0f7ff;border-left:3px solid #3498db;">';
  if (s.source_url) html += '<strong><a href="' + s.source_url + '">' + s.title + '</a></strong>';
  else html += '<strong>' + s.title + '</strong>';
  if (s.summary) html += '<br><span style="font-size:0.9em;color:#555;">' + s.summary.substring(0, 200) + '</span>';
  html += '</li>';
}
html += '</ul><hr><p style="color:#999;font-size:0.8em;">AI Market Scanner - Workhorse</p></div>';
return [{ json: { subject: 'AI & EdTech Weekly Brief - ' + now, html: html } }];
